// ─── LIGHTBOX COMPONENT ──────────────────────────────────────────────────────
function Lightbox({ project, onClose }) {
    const [current, setCurrent] = useState(0);
    const all = project.gallery;

    useEffect(() => {
        const onKey = (e) => {
            if (e.key === "Escape") onClose();
            if (e.key === "ArrowRight") setCurrent((c) => (c + 1) % all.length);
            if (e.key === "ArrowLeft") setCurrent((c) => (c - 1 + all.length) % all.length);
        };
        document.addEventListener("keydown", onKey);
        return () => document.removeEventListener("keydown", onKey);
    }, [all.length, onClose]);

    return (
        <div className="fixed inset-0 z-[100] bg-black/95 flex flex-col">
            {/* Header bar */}
            <div className="flex items-center justify-between px-6 md:px-10 py-5 border-b border-white/10 shrink-0">
                <div>
                    <p className="text-xs tracking-[0.25em] uppercase text-white/40 mb-1">
                        {project.eyebrow}
                    </p>
                    <p className="text-white font-display text-lg font-medium">
                        {current + 1} / {all.length}
                    </p>
                </div>
                <button
                    onClick={onClose}
                    className="p-2 text-white/60 hover:text-white hover:bg-white/10 rounded-full transition-colors"
                    aria-label="Close gallery"
                >
                    <X size={28} strokeWidth={1.5} />
                </button>
            </div>

            {/* Main image */}
            <div className="flex-1 relative overflow-hidden flex items-center justify-center px-4 md:px-16 py-6">
                <img
                    key={current}
                    src={all[current]}
                    alt={`${project.eyebrow} photo ${current + 1}`}
                    className="max-h-full max-w-full object-contain"
                    style={{ animation: "fadeIn 0.2s ease" }}
                />

                {/* Prev / Next */}
                <button
                    onClick={() => setCurrent((c) => (c - 1 + all.length) % all.length)}
                    className="absolute left-3 md:left-6 p-2 text-white/60 hover:text-white bg-black/40 hover:bg-black/70 rounded-full transition-colors"
                    aria-label="Previous photo"
                >
                    <ChevronLeft size={24} />
                </button>
                <button
                    onClick={() => setCurrent((c) => (c + 1) % all.length)}
                    className="absolute right-3 md:right-6 p-2 text-white/60 hover:text-white bg-black/40 hover:bg-black/70 rounded-full transition-colors"
                    aria-label="Next photo"
                >
                    <ChevronRight size={24} />
                </button>
            </div>

            {/* Thumbnail strip */}
            <div className="shrink-0 px-6 md:px-10 pb-6 pt-2">
                <div className="flex gap-2 overflow-x-auto pb-1 scrollbar-hide">
                    {all.map((src, i) => (
                        <button
                            key={i}
                            onClick={() => setCurrent(i)}
                            className={`shrink-0 w-16 h-12 md:w-20 md:h-14 overflow-hidden transition-all duration-200 ${i === current
                                    ? "ring-2 ring-white opacity-100"
                                    : "opacity-40 hover:opacity-70"
                                }`}
                        >
                            <img
                                src={src}
                                alt=""
                                className="w-full h-full object-cover"
                                loading="lazy"
                            />
                        </button>
                    ))}
                </div>
            </div>

            <style>{`@keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }`}</style>
        </div>
    );
}

// ─── PROJECT ROW ─────────────────────────────────────────────────────────────
// Alternates: even rows → image left, text right. Odd → reversed.
function ProjectRow({ project, index, onOpenGallery }) {
    const isReversed = index % 2 !== 0;

    return (
        <div
            className={`flex flex-col ${isReversed ? "lg:flex-row-reverse" : "lg:flex-row"
                } gap-0 border-t border-white/10 group`}
        >
            {/* ── Image cluster ───────────────────────────────────────── */}
            <div className="lg:w-3/5 relative overflow-hidden">
                {/* Highlight image */}
                <div className="relative aspect-[4/3] md:aspect-[16/10] overflow-hidden bg-brand-charcoal">
                    <img
                        src={project.highlight}
                        alt={project.eyebrow}
                        className="w-full h-full object-cover transition-transform duration-700 ease-out group-hover:scale-[1.03]"
                        loading="lazy"
                    />
                    {/* Subtle bottom gradient overlay */}
                    <div className="absolute inset-0 bg-gradient-to-t from-brand-ink/50 via-transparent to-transparent" />

                    {/* Floating label number */}
                    <div
                        className="absolute top-5 left-5 font-mono text-xs tracking-[0.3em] px-2.5 py-1.5"
                        style={{
                            backgroundColor: project.accent + "22",
                            border: `1px solid ${project.accent}55`,
                            color: project.accent,
                        }}
                    >
                        {project.label}
                    </div>
                </div>

                {/* Thumbnail strip below hero */}
                <div className="flex gap-1.5 p-3 bg-brand-ink/60">
                    {project.gallery.slice(0, 4).map((src, i) => (
                        <button
                            key={i}
                            onClick={() => onOpenGallery(project)}
                            className="flex-1 aspect-video overflow-hidden bg-brand-charcoal opacity-70 hover:opacity-100 transition-opacity duration-200"
                        >
                            <img src={src} alt="" className="w-full h-full object-cover" loading="lazy" />
                        </button>
                    ))}
                    {/* "More" tile */}
                    {project.gallery.length > 4 && (
                        <button
                            onClick={() => onOpenGallery(project)}
                            className="flex-1 aspect-video bg-white/5 hover:bg-white/10 transition-colors flex items-center justify-center border border-white/10"
                        >
                            <span className="text-xs text-white/50 font-medium">
                                +{project.gallery.length - 4}
                            </span>
                        </button>
                    )}
                </div>
            </div>

            {/* ── Text panel ──────────────────────────────────────────── */}
            <div className="lg:w-2/5 flex flex-col justify-center p-8 md:p-12 lg:p-14">
                {/* Eyebrow */}
                <div className="flex items-center gap-3 mb-6">
                    <span className="block w-6 h-px" style={{ backgroundColor: project.accent }} />
                    <span
                        className="text-xs tracking-[0.3em] uppercase font-medium"
                        style={{ color: project.accent }}
                    >
                        {project.eyebrow}
                    </span>
                </div>

                {/* Headline */}
                <h3 className="font-display text-2xl md:text-3xl lg:text-4xl font-medium tracking-tight text-white leading-[1.15] mb-6">
                    {project.headline}
                </h3>

                {/* Description */}
                <p className="text-white/60 text-base leading-relaxed mb-8">
                    {project.description}
                </p>

                {/* Meta grid */}
                <div className="grid grid-cols-2 gap-x-6 gap-y-4 border-t border-white/10 pt-8 mb-10">
                    <div>
                        <p className="text-[11px] uppercase tracking-[0.25em] text-white/35 mb-1">Scope</p>
                        <p className="text-sm font-medium text-white/85">{project.scope}</p>
                    </div>
                    <div>
                        <p className="text-[11px] uppercase tracking-[0.25em] text-white/35 mb-1">Timeline</p>
                        <p className="text-sm font-medium text-white/85">{project.timeline}</p>
                    </div>
                    <div>
                        <p className="text-[11px] uppercase tracking-[0.25em] text-white/35 mb-1">Location</p>
                        <p className="text-sm font-medium text-white/85">Springwater, ON</p>
                    </div>
                    <div>
                        <p className="text-[11px] uppercase tracking-[0.25em] text-white/35 mb-1">Photos</p>
                        <p className="text-sm font-medium text-white/85">{project.gallery.length} images</p>
                    </div>
                </div>

                {/* CTA */}
                <button
                    onClick={() => onOpenGallery(project)}
                    className="group self-start inline-flex items-center gap-3 text-xs font-bold tracking-[0.25em] uppercase transition-colors"
                    style={{ color: project.accent }}
                >
                    View Full Gallery
                    <ArrowUpRight
                        size={15}
                        className="group-hover:translate-x-0.5 group-hover:-translate-y-0.5 transition-transform"
                    />
                </button>
            </div>
        </div>
    );
}

